const listPingLatencyMinRollupSeries = `-- name: ListPingLatencyMinRollupSeries :many
WITH settings AS (
    SELECT (
        greatest(
            60,
            ceil(extract(epoch FROM ($1::timestamptz - $2::timestamptz)) / $3::double precision)::bigint
        ) * interval '1 second'
    ) AS bucket_width
),
bucketed AS (
    SELECT
        time_bucket(settings.bucket_width, bucket, $2::timestamptz) AS query_bucket,
        rtt_avg_count,
        rtt_min_ms
    FROM ping_result_rollups_1m
    CROSS JOIN settings
    WHERE probe_id = $4
        AND check_id = $5
        AND bucket >= $2
        AND bucket < $1
)
SELECT
    (extract(epoch FROM query_bucket) * 1000)::bigint AS bucket_ms,
    coalesce(min(rtt_min_ms), 0)::double precision AS value
FROM bucketed
GROUP BY query_bucket
HAVING sum(rtt_avg_count) > 0
ORDER BY query_bucket ASC
`

